```plantuml
@startuml
title Get Park Reviews Activity

skinparam packageStyle rectangle
skinparam actor {
  BackgroundColor<<Actor>> #E6E6FA
}
skinparam database {
  BackgroundColor<<Database>> #E6E6FA
}
skinparam component {
  BackgroundColor<<Component>> #E6E6FA
}

rectangle "Front End" as FrontEnd {
  actor "Client" as Client1
}

rectangle "Back End" as BackEnd {
  component "Website Park Page" as WebsiteParkPage
  component "GetParkReviewsActivity" as GetParkReviewsActivity
  database "Reviews" as ReviewsDB
}

rectangle "Front End" as FrontEnd2 {
  actor "Client" as Client2
}

rectangle "Back End" as BackEnd2 {
  component "Website Park Page" as WebsiteParkPage2
  component "GetParkReviewsActivity" as GetParkReviewsActivity2
  database "Reviews" as ReviewsDB2
}

Client1 -> WebsiteParkPage : Visit park page
activate WebsiteParkPage
WebsiteParkPage -> GetParkReviewsActivity : Send get reviews request
activate GetParkReviewsActivity
GetParkReviewsActivity -> ReviewsDB : Get reviews
activate ReviewsDB
ReviewsDB --> GetParkReviewsActivity : Reviews item
deactivate ReviewsDB
GetParkReviewsActivity --> WebsiteParkPage : ReviewsModel
deactivate GetParkReviewsActivity
WebsiteParkPage --> Client2 : Present reviews
deactivate WebsiteParkPage

@enduml
```
